SELECT DRAW_NO, USER_ID, GRP_NO, DEV_KIND1, DEV_KIND2, POS_X, POS_Y, WIDTH, HEIGHT, FILL_COLOR, FILL_OPACITY, STROKE_COLOR, STROKE_OPACITY, STROKE_WIDTH, CORNER_RADIUS, FONT_SIZE, FONT_WEIGHT, TEXT_ANCHOR, CASE DEV_KIND1 WHEN 'DRAW_TEXT_AREA' THEN TEXT_AREA_CONTENT ELSE TEXT_CONTENT END AS TEXT_CONTENT, RX, RY, SORT_IDX, COALESCE(FONT_DISTANCE, 20) AS FONT_DISTANCE, COALESCE(ROTATION, 0) AS ROTATION, COALESCE(LINE_STYLE, '') AS LINE_STYLE, DRAW_CONF FROM CM_TOPO_DRAW_TOOL WHERE USER_ID = AND GRP_NO = #{grpNo}
AND DRAW_NO = #{drawNo}
ORDER BY SORT_IDX

